# Dynamic context assembly: decide what to include per query rather than
# always injecting all sources. Skip a source if it is irrelevant to save tokens.

from openai import OpenAI

client = OpenAI(api_key="...")

def needs_memory(query: str) -> bool:
    """Heuristic: skip memory retrieval for greetings or trivial questions."""
    trivial = {"hi", "hello", "thanks", "ok", "yes", "no"}
    return query.lower().strip().rstrip("!?.") not in trivial

def needs_tool_results(query: str, available_tools: list[str]) -> bool:
    """Check if query keywords suggest a tool call is needed."""
    tool_keywords = {
        "weather": "weather_tool",
        "calculate": "calculator",
        "search": "web_search",
        "file": "file_reader",
    }
    return any(kw in query.lower() for kw in tool_keywords)

def dynamic_assemble(
    query: str,
    system_prompt: str,
    memory_store,           # callable: query → str
    tool_runner,            # callable: query → str | None
) -> list[dict]:
    system = system_prompt

    if needs_memory(query):
        facts = memory_store(query)           # only call if likely useful
        if facts:
            system += f"\n\n[Memory]\n{facts}"

    user_content = query
    if needs_tool_results(query, []):
        tool_out = tool_runner(query)         # only run if likely useful
        if tool_out:
            user_content = f"[Tool result]\n{tool_out}\n\n{query}"

    return [
        {"role": "system", "content": system},
        {"role": "user",   "content": user_content},
    ]
